java_files['app/src/main/java/com/fountainhome/streaming/CrashLogger.java'] = 'package com.fountainhome.streaming;\nimport android.content.Context;\nimport java.io.*;\nimport java.text.SimpleDateFormat;\nimport java.util.*;\npublic class CrashLogger {\n    public static void init(Context ctx) {\n        Thread.setDefaultUncaughtExceptionHandler((thread, throwable) -> {\n            try {\n                File f = new File(ctx.getExternalFilesDir(null), "crash_log.txt");\n                PrintWriter pw = new PrintWriter(new FileWriter(f, false));\n                pw.println("=== CRASH " + new SimpleDateFormat("HH:mm:ss", Locale.US).format(new Date()) + " ===");\n                pw.println(throwable.toString());\n                for (StackTraceElement e : throwable.getStackTrace()) pw.println("  at " + e);\n                if (throwable.getCause() != null) {\n                    pw.println("CAUSED BY: " + throwable.getCause());\n                    for (StackTraceElement e : throwable.getCause().getStackTrace()) pw.println("  at " + e);\n                }\n                pw.flush(); pw.close();\n            } catch (Exception ignored) {}\n            android.os.Process.killProcess(android.os.Process.myPid());\n        });\n    }\n    public static String read(Context ctx) {\n        try {\n            File f = new File(ctx.getExternalFilesDir(null), "crash_log.txt");\n            if (!f.exists()) return "No crash log yet.";\n            BufferedReader br = new BufferedReader(new FileReader(f));\n            StringBuilder sb = new StringBuilder();\n            String line;\n            while ((line = br.readLine()) != null) sb.append(line).append("\n");\n            br.close();\n            return sb.toString();\n        } catch (Exception e) { return "Error: " + e.getMessage(); }\n    }\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/GlideConfig.java'] = 'package com.fountainhome.streaming;\nimport android.content.Context;\nimport androidx.annotation.NonNull;\nimport com.bumptech.glide.GlideBuilder;\nimport com.bumptech.glide.annotation.GlideModule;\nimport com.bumptech.glide.load.engine.cache.InternalCacheDiskCacheFactory;\nimport com.bumptech.glide.load.engine.cache.LruResourceCache;\nimport com.bumptech.glide.module.AppGlideModule;\n@GlideModule\npublic class GlideConfig extends AppGlideModule {\n    @Override public void applyOptions(@NonNull Context c, @NonNull GlideBuilder b) {\n        b.setMemoryCache(new LruResourceCache(20*1024*1024));\n        b.setDiskCache(new InternalCacheDiskCacheFactory(c,"image_cache",100*1024*1024));\n    }\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/service/AppPreferences.java'] = 'package com.fountainhome.streaming.service;\nimport android.content.Context;\nimport android.content.SharedPreferences;\nimport android.graphics.Color;\npublic class AppPreferences {\n    private static final String PREFS="fh_prefs";\n    public static final String COLOR_PURPLE="#BB86FC",COLOR_BLUE="#2196F3",COLOR_RED="#CF6679";\n    public static final String COLOR_GREEN="#4CAF50",COLOR_ORANGE="#FF9800",COLOR_PINK="#E91E8C",COLOR_TEAL="#03DAC6";\n    public static final String STATUS_NONE="none",STATUS_PLAN="planning",STATUS_WATCH="watching",STATUS_DONE="watched",STATUS_DROP="dropped";\n    private static SharedPreferences p(Context c){return c.getSharedPreferences(PREFS,0);}\n    public static String  getAccent(Context c)              {return p(c).getString("accent",COLOR_PURPLE);}\n    public static void    setAccent(Context c,String v)     {p(c).edit().putString("accent",v).apply();}\n    public static int     getAccentColor(Context c)         {try{return Color.parseColor(getAccent(c));}catch(Exception e){return Color.parseColor(COLOR_PURPLE);}}\n    public static String  getSource(Context c)              {return p(c).getString("source","VidSrc");}\n    public static void    setSource(Context c,String v)     {p(c).edit().putString("source",v).apply();}\n    public static String  getAnimeDubSub(Context c)         {return p(c).getString("dub_sub","sub");}\n    public static void    setAnimeDubSub(Context c,String v){p(c).edit().putString("dub_sub",v).apply();}\n    public static boolean getAutoplay(Context c)            {return p(c).getBoolean("autoplay",true);}\n    public static void    setAutoplay(Context c,boolean v)  {p(c).edit().putBoolean("autoplay",v).apply();}\n    public static boolean getPiP(Context c)                 {return p(c).getBoolean("pip",true);}\n    public static void    setPiP(Context c,boolean v)       {p(c).edit().putBoolean("pip",v).apply();}\n    public static String  getSubLang(Context c)             {return p(c).getString("sub_lang","en");}\n    public static void    setSubLang(Context c,String v)    {p(c).edit().putString("sub_lang",v).apply();}\n    public static boolean getWifiOnly(Context c)            {return p(c).getBoolean("wifi_only",false);}\n    public static void    setWifiOnly(Context c,boolean v)  {p(c).edit().putBoolean("wifi_only",v).apply();}\n    public static String  getDlQuality(Context c)           {return p(c).getString("dl_quality","720p");}\n    public static void    setDlQuality(Context c,String v)  {p(c).edit().putString("dl_quality",v).apply();}\n    public static boolean getShowContinue(Context c)        {return p(c).getBoolean("show_continue",true);}\n    public static void    setShowContinue(Context c,boolean v){p(c).edit().putBoolean("show_continue",v).apply();}\n    public static float   getPlaybackSpeed(Context c)       {return p(c).getFloat("speed",1.0f);}\n    public static void    setPlaybackSpeed(Context c,float v){p(c).edit().putFloat("speed",v).apply();}\n    public static String  getItemStatus(Context c,int id,String type){return p(c).getString("status_"+type+"_"+id,STATUS_NONE);}\n    public static void    setItemStatus(Context c,int id,String type,String status){p(c).edit().putString("status_"+type+"_"+id,status).apply();}\n    public static void    clearAll(Context c)               {p(c).edit().clear().apply();}\n    public static int     getSurfaceColor(Context c)        {return Color.parseColor("#141414");}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/service/WatchProgress.java'] = 'package com.fountainhome.streaming.service;\nimport android.content.Context;\nimport android.content.SharedPreferences;\npublic class WatchProgress {\n    private static final String PREFS="fh_progress";\n    private static SharedPreferences p(Context c){return c.getSharedPreferences(PREFS,0);}\n    public static void save(Context c,int id,String t,int s,int e,long ms){p(c).edit().putLong(key(id,t,s,e),ms).apply();}\n    public static long get(Context c,int id,String t,int s,int e){return p(c).getLong(key(id,t,s,e),0L);}\n    public static void clear(Context c,int id,String t,int s,int e){p(c).edit().remove(key(id,t,s,e)).apply();}\n    private static String key(int id,String t,int s,int e){return t+"_"+id+"_s"+s+"_e"+e;}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/service/LibraryManager.java'] = 'package com.fountainhome.streaming.service;\nimport android.content.Context;\nimport android.content.SharedPreferences;\nimport com.fountainhome.streaming.ui.viewmodel.ContentItem;\nimport com.google.gson.Gson;\nimport com.google.gson.reflect.TypeToken;\nimport java.lang.reflect.Type;\nimport java.util.ArrayList;\nimport java.util.List;\npublic class LibraryManager {\n    public static final String FAVORITES="favorites",WATCHLIST="watchlist",CONTINUE="continue";\n    private static final Gson gson=new Gson();\n    private static SharedPreferences p(Context c){return c.getSharedPreferences("fh_library",0);}\n    public static void add(Context c,ContentItem item,String list){List<ContentItem>items=get(c,list);items.removeIf(i->i.id==item.id&&eq(i.mediaType,item.mediaType));items.add(0,item);if(CONTINUE.equals(list)&&items.size()>100)items=items.subList(0,100);p(c).edit().putString(list,gson.toJson(items)).apply();}\n    public static void remove(Context c,int id,String mt,String list){List<ContentItem>items=get(c,list);items.removeIf(i->i.id==id&&eq(i.mediaType,mt));p(c).edit().putString(list,gson.toJson(items)).apply();}\n    public static boolean isIn(Context c,int id,String mt,String list){for(ContentItem i:get(c,list))if(i.id==id&&eq(i.mediaType,mt))return true;return false;}\n    public static List<ContentItem>get(Context c,String list){String json=p(c).getString(list,"[]");Type type=new TypeToken<List<ContentItem>>(){}.getType();try{List<ContentItem>items=gson.fromJson(json,type);return items!=null?items:new ArrayList<>();}catch(Exception e){return new ArrayList<>();}}\n    public static void clearList(Context c,String list){p(c).edit().remove(list).apply();}\n    public static void toggleFavorite(Context c,ContentItem item){if(isIn(c,item.id,item.mediaType,FAVORITES))remove(c,item.id,item.mediaType,FAVORITES);else add(c,item,FAVORITES);}\n    public static void updateProgress(Context c,ContentItem item,int s,int e,long ms){item.lastSeason=s;item.lastEpisode=e;item.lastPositionMs=ms;add(c,item,CONTINUE);WatchProgress.save(c,item.id,item.mediaType,s,e,ms);}\n    private static boolean eq(String a,String b){return a==null?b==null:a.equals(b);}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/service/SourceGenerator.java'] = 'package com.fountainhome.streaming.service;\nimport java.util.ArrayList;\nimport java.util.List;\npublic class SourceGenerator {\n    public static class Source{public final String url,label;public Source(String u,String l){url=u;label=l;}}\n    public static List<Source>getMovieSources(String imdbId,int tmdbId){\n        List<Source>l=new ArrayList<>();boolean has=imdbId!=null&&!imdbId.isEmpty();\n        l.add(new Source("https://vsembed.ru/embed/movie?tmdb="+tmdbId,"VidSrc"));\n        if(has){l.add(new Source("https://www.2embed.online/2embed.php?id="+imdbId,"2Embed"));l.add(new Source("https://autoembed.cc/movie/imdb/"+imdbId,"AutoEmbed"));l.add(new Source("https://multiembed.mov/directstream.php?video_id="+imdbId,"SuperEmbed VIP"));l.add(new Source("https://multiembed.mov/?video_id="+imdbId,"SuperEmbed"));}\n        l.add(new Source("https://www.2embed.online/2embed.php?id="+tmdbId,"2Embed(T)"));\n        l.add(new Source("https://autoembed.cc/movie/tmdb/"+tmdbId,"AutoEmbed(T)"));\n        return l;\n    }\n    public static List<Source>getTVSources(String imdbId,int tmdbId,int s,int e){\n        List<Source>l=new ArrayList<>();boolean has=imdbId!=null&&!imdbId.isEmpty();\n        l.add(new Source("https://vsembed.ru/embed/tv?tmdb="+tmdbId+"&season="+s+"&episode="+e,"VidSrc"));\n        if(has){l.add(new Source("https://www.2embed.online/tv-2embed.php?id="+imdbId+"&season="+s+"&episode="+e,"2Embed"));l.add(new Source("https://autoembed.cc/tv/imdb/"+imdbId+"/"+s+"/"+e,"AutoEmbed"));l.add(new Source("https://multiembed.mov/directstream.php?video_id="+imdbId+"&s="+s+"&e="+e,"SuperEmbed VIP"));l.add(new Source("https://multiembed.mov/?video_id="+imdbId+"&s="+s+"&e="+e,"SuperEmbed"));}\n        l.add(new Source("https://www.2embed.online/tv-2embed.php?id="+tmdbId+"&season="+s+"&episode="+e,"2Embed(T)"));\n        l.add(new Source("https://autoembed.cc/tv/tmdb/"+tmdbId+"/"+s+"/"+e,"AutoEmbed(T)"));\n        return l;\n    }\n    public static String imageUrl(String path,String size){if(path==null||path.isEmpty())return "";return "https://image.tmdb.org/t/p/"+size+path;}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/service/AdBlockWebViewClient.java'] = 'package com.fountainhome.streaming.service;\nimport android.webkit.*;\nimport java.io.ByteArrayInputStream;\nimport java.util.Arrays;\nimport java.util.List;\npublic class AdBlockWebViewClient extends WebViewClient {\n    private static final List<String>BLOCK=Arrays.asList("doubleclick.net","googlesyndication.com","googleadservices.com","outbrain.com","taboola.com","exoclick.com","juicyads.com","trafficjunky.net","popads.net","popcash.net","adsterra.com","propellerads.com","criteo.com","media.net","pubmatic.com","appnexus.com","clickadu.com","coinzilla.com","adfoc.us","bc.vc","shorte.st","ouo.io","linkvertise.com");\n    private static final WebResourceResponse EMPTY=new WebResourceResponse("text/plain","utf-8",new ByteArrayInputStream("".getBytes()));\n    @Override public WebResourceResponse shouldInterceptRequest(WebView v,WebResourceRequest r){String url=r.getUrl().toString().toLowerCase();for(String b:BLOCK)if(url.contains(b))return EMPTY;return null;}\n    @Override public boolean shouldOverrideUrlLoading(WebView v,WebResourceRequest r){String url=r.getUrl().toString().toLowerCase();for(String b:BLOCK)if(url.contains(b))return true;String host=r.getUrl().getHost();if(host==null)return false;List<String>OK=Arrays.asList("vsembed.ru","2embed.online","2embed.cc","autoembed.cc","multiembed.mov","vidsrc.xyz","vidsrc.me","themoviedb.org","image.tmdb.org");for(String a:OK)if(host.contains(a))return false;if(host.contains("embed")||host.contains("vid")||host.contains("stream"))return false;return url.contains("redirect")||url.contains("popup");}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/service/StreamExtractor.java'] = 'package com.fountainhome.streaming.service;\nimport android.annotation.SuppressLint;\nimport android.content.Context;\nimport android.os.Handler;\nimport android.os.Looper;\nimport android.webkit.*;\nimport java.util.HashMap;\nimport java.util.Map;\nimport java.util.concurrent.atomic.AtomicBoolean;\npublic class StreamExtractor {\n    public interface Callback{void onFound(String url,Map<String,String>headers);void onFailed();}\n    private static final String[]PATTERNS={".m3u8","master.m3u8","/hls/","index.m3u8",".mp4?"};\n    private WebView wv;\n    private final Handler h=new Handler(Looper.getMainLooper());\n    private final AtomicBoolean found=new AtomicBoolean(false);\n    @SuppressLint("SetJavaScriptEnabled")\n    public void extract(Context ctx,String embedUrl,int timeoutMs,Callback cb){\n        found.set(false);\n        h.post(()->{\n            wv=new WebView(ctx.getApplicationContext());\n            WebSettings ws=wv.getSettings();\n            ws.setJavaScriptEnabled(true);ws.setDomStorageEnabled(true);\n            ws.setMediaPlaybackRequiresUserGesture(false);\n            ws.setMixedContentMode(WebSettings.MIXED_CONTENT_ALWAYS_ALLOW);\n            ws.setUserAgentString("Mozilla/5.0 (Linux; Android 13; Pixel 7) AppleWebKit/537.36 Chrome/120.0.0.0 Mobile Safari/537.36");\n            wv.setWebViewClient(new WebViewClient(){\n                @Override public WebResourceResponse shouldInterceptRequest(WebView v,WebResourceRequest r){\n                    if(found.get())return null;\n                    String url=r.getUrl().toString().toLowerCase();\n                    for(String p:PATTERNS)if(url.contains(p)){\n                        found.set(true);\n                        Map<String,String>hd=new HashMap<>(r.getRequestHeaders());\n                        hd.put("Referer",embedUrl);\n                        h.post(()->{cb.onFound(r.getUrl().toString(),hd);destroy();});\n                        break;\n                    }\n                    return null;\n                }\n            });\n            String html="<!DOCTYPE html><html><head><style>*{margin:0;padding:0;background:#000}iframe{width:100vw;height:100vh;border:none}</style></head><body><iframe src=\'"+embedUrl+"\' allowfullscreen allow=\'autoplay;fullscreen\'></iframe></body></html>";\n            wv.loadDataWithBaseURL("https://www.google.com",html,"text/html","utf-8",null);\n            h.postDelayed(()->{if(!found.get()){found.set(true);cb.onFailed();destroy();}},timeoutMs);\n        });\n    }\n    private void destroy(){h.post(()->{if(wv!=null){wv.stopLoading();wv.destroy();wv=null;}});}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/service/DownloadService.java'] = 'package com.fountainhome.streaming.service;\nimport android.app.*;\nimport android.content.Intent;\nimport android.os.*;\nimport androidx.annotation.Nullable;\nimport androidx.core.app.NotificationCompat;\npublic class DownloadService extends Service {\n    private static final String CH="fh_dl";\n    @Override public void onCreate(){super.onCreate();if(Build.VERSION.SDK_INT>=26){NotificationChannel ch=new NotificationChannel(CH,"Downloads",NotificationManager.IMPORTANCE_LOW);((NotificationManager)getSystemService(NOTIFICATION_SERVICE)).createNotificationChannel(ch);}Notification n=new NotificationCompat.Builder(this,CH).setContentTitle("Fountain Home").setContentText("Downloading...").setSmallIcon(android.R.drawable.stat_sys_download_done).build();startForeground(1,n);}\n    @Override public int onStartCommand(Intent i,int f,int s){return START_NOT_STICKY;}\n    @Nullable @Override public IBinder onBind(Intent i){return null;}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/download/DownloadItem.java'] = 'package com.fountainhome.streaming.download;\nimport androidx.room.Entity;\nimport androidx.room.PrimaryKey;\n@Entity(tableName="downloads")\npublic class DownloadItem {\n    @PrimaryKey(autoGenerate=true) public int id;\n    public int tmdbId,season,episode;\n    public String type,title,posterPath,localPath,status,imdbId,overview;\n    public long addedAt; public double rating; public boolean isOfflineReady;\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/download/DownloadDao.java'] = 'package com.fountainhome.streaming.download;\nimport androidx.lifecycle.LiveData;\nimport androidx.room.*;\nimport java.util.List;\n@Dao public interface DownloadDao {\n    @Insert void insert(DownloadItem i);\n    @Update void update(DownloadItem i);\n    @Delete void delete(DownloadItem i);\n    @Query("SELECT * FROM downloads ORDER BY addedAt DESC") LiveData<List<DownloadItem>> getAll();\n    @Query("SELECT * FROM downloads WHERE status=\'completed\'") LiveData<List<DownloadItem>> getCompleted();\n    @Query("SELECT * FROM downloads WHERE tmdbId=:t AND type=:tp AND season=:s AND episode=:e LIMIT 1") DownloadItem find(int t,String tp,int s,int e);\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/download/AppDatabase.java'] = 'package com.fountainhome.streaming.download;\nimport android.content.Context;\nimport androidx.room.*;\n@Database(entities={DownloadItem.class},version=1,exportSchema=false)\npublic abstract class AppDatabase extends RoomDatabase {\n    private static volatile AppDatabase inst;\n    public abstract DownloadDao downloadDao();\n    public static synchronized AppDatabase get(Context c){if(inst==null)inst=Room.databaseBuilder(c.getApplicationContext(),AppDatabase.class,"fh_db").allowMainThreadQueries().fallbackToDestructiveMigration().build();return inst;}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/download/DownloadManager2.java'] = 'package com.fountainhome.streaming.download;\nimport android.content.Context;\nimport com.fountainhome.streaming.ui.viewmodel.ContentItem;\nimport java.io.File;\nimport java.util.concurrent.ExecutorService;\nimport java.util.concurrent.Executors;\npublic class DownloadManager2 {\n    private static final ExecutorService exec=Executors.newFixedThreadPool(2);\n    public static void saveForOffline(Context ctx,ContentItem item){exec.execute(()->{DownloadItem dl=new DownloadItem();dl.tmdbId=item.id;dl.type=item.mediaType;dl.title=item.displayTitle();dl.posterPath=item.posterPath;dl.overview=item.overview;dl.rating=item.rating;dl.imdbId=item.imdbId;dl.season=item.lastSeason;dl.episode=item.lastEpisode;dl.status="completed";dl.isOfflineReady=false;dl.addedAt=System.currentTimeMillis();AppDatabase.get(ctx).downloadDao().insert(dl);});}\n    public static boolean isDownloaded(Context ctx,int tmdbId,String type,int s,int e){DownloadItem dl=AppDatabase.get(ctx).downloadDao().find(tmdbId,type,s,e);return dl!=null&&"completed".equals(dl.status)&&dl.localPath!=null&&new File(dl.localPath).exists();}\n    public static void deleteDownload(Context ctx,DownloadItem item){exec.execute(()->{if(item.localPath!=null)new File(item.localPath).delete();AppDatabase.get(ctx).downloadDao().delete(item);});}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/api/Models.java'] = 'package com.fountainhome.streaming.api;\nimport java.util.List;\npublic class Models {\n    public static class PagedResponse<T>{public int page;public List<T>results;}\n    public static class MovieResult{public int id;public String title,overview,poster_path,backdrop_path,release_date;public double vote_average;}\n    public static class TVResult{public int id;public String name,overview,poster_path,backdrop_path,first_air_date;public double vote_average;}\n    public static class SearchResult{public String media_type;public int id;public String title,name,poster_path;public double vote_average;}\n    public static class MovieDetail{public int id,runtime;public String imdb_id,title,overview,poster_path,backdrop_path,release_date;public double vote_average;}\n    public static class TVDetail{public int id,number_of_seasons;public String name,overview,poster_path,backdrop_path,first_air_date;public double vote_average;public List<Season>seasons;}\n    public static class SeasonDetail{public int season_number;public String name;public List<Episode>episodes;}\n    public static class Episode{public int episode_number,runtime;public String name,overview,still_path,air_date;public double vote_average;}\n    public static class Season{public int season_number,episode_count;public String name,poster_path;}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/api/TMDBService.java'] = 'package com.fountainhome.streaming.api;\nimport retrofit2.Call;\nimport retrofit2.http.*;\npublic interface TMDBService {\n    @GET("movie/popular")     Call<Models.PagedResponse<Models.MovieResult>> getPopularMovies(@Query("page") int p);\n    @GET("tv/popular")        Call<Models.PagedResponse<Models.TVResult>>    getPopularTV(@Query("page") int p);\n    @GET("movie/now_playing") Call<Models.PagedResponse<Models.MovieResult>> getNowPlaying(@Query("page") int p);\n    @GET("movie/top_rated")   Call<Models.PagedResponse<Models.MovieResult>> getTopRatedMovies(@Query("page") int p);\n    @GET("tv/top_rated")      Call<Models.PagedResponse<Models.TVResult>>    getTopRatedTV(@Query("page") int p);\n    @GET("tv/on_the_air")     Call<Models.PagedResponse<Models.TVResult>>    getOnAirTV(@Query("page") int p);\n    @GET("search/multi")      Call<Models.PagedResponse<Models.SearchResult>>search(@Query("query") String q,@Query("page") int p);\n    @GET("movie/{id}")        Call<Models.MovieDetail> getMovieDetail(@Path("id") int id,@Query("append_to_response") String a);\n    @GET("tv/{id}")           Call<Models.TVDetail>    getTVDetail(@Path("id") int id,@Query("append_to_response") String a);\n    @GET("movie/{id}/similar") Call<Models.PagedResponse<Models.MovieResult>> getSimilarMovies(@Path("id") int id);\n    @GET("tv/{id}/similar")    Call<Models.PagedResponse<Models.TVResult>>    getSimilarTV(@Path("id") int id);\n    @GET("tv/{id}/season/{s}") Call<Models.SeasonDetail> getSeason(@Path("id") int id,@Path("s") int s);\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/api/TMDBClient.java'] = 'package com.fountainhome.streaming.api;\nimport com.fountainhome.streaming.BuildConfig;\nimport okhttp3.*;\nimport retrofit2.Retrofit;\nimport retrofit2.converter.gson.GsonConverterFactory;\npublic class TMDBClient {\n    private static final String BASE="https://api.themoviedb.org/3/";\n    private static volatile TMDBService inst;\n    public static synchronized TMDBService get(){\n        if(inst==null){\n            OkHttpClient client=new OkHttpClient.Builder()\n                .addNetworkInterceptor(chain->{Request req=chain.request().newBuilder().header("Accept-Encoding","identity").header("Accept","application/json").build();Response res=chain.proceed(req);return res.newBuilder().header("Cache-Control","public, max-age=3600").build();})\n                .addInterceptor(chain->{HttpUrl url=chain.request().url().newBuilder().addQueryParameter("api_key",BuildConfig.TMDB_API_KEY).build();return chain.proceed(chain.request().newBuilder().url(url).build());}).build();\n            inst=new Retrofit.Builder().baseUrl(BASE).client(client).addConverterFactory(GsonConverterFactory.create()).build().create(TMDBService.class);\n        }\n        return inst;\n    }\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/ui/viewmodel/ContentItem.java'] = 'package com.fountainhome.streaming.ui.viewmodel;\npublic class ContentItem {\n    public int id,numberOfSeasons,runtime,lastSeason=1,lastEpisode=1;\n    public long lastPositionMs=0;\n    public String title,name,posterPath,backdropPath,mediaType,imdbId,overview,releaseDate;\n    public double rating; public boolean isAnime=false;\n    public String displayTitle(){return title!=null&&!title.isEmpty()?title:(name!=null?name:"");}\n    public String year(){String d=releaseDate!=null?releaseDate:"";return d.length()>=4?d.substring(0,4):"";}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/ui/viewmodel/HomeViewModel.java'] = 'package com.fountainhome.streaming.ui.viewmodel;\nimport android.app.Application;\nimport android.os.Handler;\nimport android.os.Looper;\nimport androidx.annotation.NonNull;\nimport androidx.lifecycle.*;\nimport com.fountainhome.streaming.api.*;\nimport java.util.*;\nimport retrofit2.*;\npublic class HomeViewModel extends AndroidViewModel {\n    private final MutableLiveData<ContentItem> featured=new MutableLiveData<>();\n    private final MutableLiveData<List<ContentItem>> popularMovies=new MutableLiveData<>(),popularTV=new MutableLiveData<>(),topRated=new MutableLiveData<>(),nowPlaying=new MutableLiveData<>();\n    private final MutableLiveData<String> error=new MutableLiveData<>();\n    private final Handler hero=new Handler(Looper.getMainLooper());\n    private final List<ContentItem> heroItems=new ArrayList<>();\n    private int heroIdx=0;private boolean cleared=false;private Runnable heroR;\n    public HomeViewModel(@NonNull Application app){super(app);load();}\n    public void load(){loadMovies();loadTV();loadTopRated();loadNowPlaying();}\n    private void loadMovies(){TMDBClient.get().getPopularMovies(1).enqueue(new Callback<Models.PagedResponse<Models.MovieResult>>(){public void onResponse(@NonNull Call<Models.PagedResponse<Models.MovieResult>>c,@NonNull Response<Models.PagedResponse<Models.MovieResult>>r){if(cleared)return;if(r.isSuccessful()&&r.body()!=null&&r.body().results!=null){List<ContentItem>items=toMovie(r.body().results);popularMovies.postValue(items);if(!items.isEmpty()){heroItems.clear();heroItems.addAll(items.subList(0,Math.min(10,items.size())));featured.postValue(heroItems.get(0));startHero();}}}public void onFailure(@NonNull Call<Models.PagedResponse<Models.MovieResult>>c,@NonNull Throwable t){if(!cleared)error.postValue(t.getMessage());}});}\n    private void startHero(){if(heroR!=null)hero.removeCallbacks(heroR);heroR=new Runnable(){@Override public void run(){if(cleared||heroItems.isEmpty())return;heroIdx=(heroIdx+1)%heroItems.size();featured.postValue(heroItems.get(heroIdx));hero.postDelayed(this,5000);}};hero.postDelayed(heroR,5000);}\n    private void loadTV(){TMDBClient.get().getPopularTV(1).enqueue(new Callback<Models.PagedResponse<Models.TVResult>>(){public void onResponse(@NonNull Call<Models.PagedResponse<Models.TVResult>>c,@NonNull Response<Models.PagedResponse<Models.TVResult>>r){if(!cleared&&r.isSuccessful()&&r.body()!=null)popularTV.postValue(toTV(r.body().results));}public void onFailure(@NonNull Call<Models.PagedResponse<Models.TVResult>>c,@NonNull Throwable t){}});}\n    private void loadTopRated(){TMDBClient.get().getTopRatedMovies(1).enqueue(new Callback<Models.PagedResponse<Models.MovieResult>>(){public void onResponse(@NonNull Call<Models.PagedResponse<Models.MovieResult>>c,@NonNull Response<Models.PagedResponse<Models.MovieResult>>r){if(!cleared&&r.isSuccessful()&&r.body()!=null)topRated.postValue(toMovie(r.body().results));}public void onFailure(@NonNull Call<Models.PagedResponse<Models.MovieResult>>c,@NonNull Throwable t){}});}\n    private void loadNowPlaying(){TMDBClient.get().getNowPlaying(1).enqueue(new Callback<Models.PagedResponse<Models.MovieResult>>(){public void onResponse(@NonNull Call<Models.PagedResponse<Models.MovieResult>>c,@NonNull Response<Models.PagedResponse<Models.MovieResult>>r){if(!cleared&&r.isSuccessful()&&r.body()!=null)nowPlaying.postValue(toMovie(r.body().results));}public void onFailure(@NonNull Call<Models.PagedResponse<Models.MovieResult>>c,@NonNull Throwable t){}});}\n    private List<ContentItem>toMovie(List<Models.MovieResult>rs){List<ContentItem>l=new ArrayList<>();if(rs==null)return l;for(Models.MovieResult r:rs){ContentItem ci=new ContentItem();ci.id=r.id;ci.title=r.title;ci.posterPath=r.poster_path;ci.backdropPath=r.backdrop_path;ci.rating=r.vote_average;ci.mediaType="movie";ci.releaseDate=r.release_date;l.add(ci);}return l;}\n    private List<ContentItem>toTV(List<Models.TVResult>rs){List<ContentItem>l=new ArrayList<>();if(rs==null)return l;for(Models.TVResult r:rs){ContentItem ci=new ContentItem();ci.id=r.id;ci.name=r.name;ci.posterPath=r.poster_path;ci.backdropPath=r.backdrop_path;ci.rating=r.vote_average;ci.mediaType="tv";l.add(ci);}return l;}\n    @Override protected void onCleared(){cleared=true;if(heroR!=null)hero.removeCallbacks(heroR);super.onCleared();}\n    public LiveData<ContentItem>getFeatured(){return featured;}\n    public LiveData<List<ContentItem>>getPopularMovies(){return popularMovies;}\n    public LiveData<List<ContentItem>>getPopularTV(){return popularTV;}\n    public LiveData<List<ContentItem>>getTopRated(){return topRated;}\n    public LiveData<List<ContentItem>>getNowPlaying(){return nowPlaying;}\n    public LiveData<String>getError(){return error;}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/ui/viewmodel/WatchViewModel.java'] = 'package com.fountainhome.streaming.ui.viewmodel;\nimport android.app.Application;\nimport androidx.annotation.NonNull;\nimport androidx.lifecycle.*;\nimport com.fountainhome.streaming.api.*;\nimport java.util.*;\nimport retrofit2.*;\npublic class WatchViewModel extends AndroidViewModel {\n    private final MutableLiveData<ContentItem>content=new MutableLiveData<>();\n    private final MutableLiveData<List<ContentItem>>similar=new MutableLiveData<>();\n    private final MutableLiveData<Models.SeasonDetail>season=new MutableLiveData<>();\n    private final MutableLiveData<Boolean>loading=new MutableLiveData<>(true);\n    public WatchViewModel(@NonNull Application app){super(app);}\n    public void load(String type,int id){loading.postValue(true);if("movie".equals(type))loadMovie(id);else loadTV(id);}\n    private void loadMovie(int id){TMDBClient.get().getMovieDetail(id,"credits").enqueue(new Callback<Models.MovieDetail>(){public void onResponse(@NonNull Call<Models.MovieDetail>c,@NonNull Response<Models.MovieDetail>r){loading.postValue(false);if(r.isSuccessful()&&r.body()!=null){Models.MovieDetail d=r.body();ContentItem ci=new ContentItem();ci.id=d.id;ci.title=d.title;ci.imdbId=d.imdb_id;ci.posterPath=d.poster_path;ci.backdropPath=d.backdrop_path;ci.rating=d.vote_average;ci.runtime=d.runtime;ci.overview=d.overview;ci.releaseDate=d.release_date;ci.mediaType="movie";content.postValue(ci);}}public void onFailure(@NonNull Call<Models.MovieDetail>c,@NonNull Throwable t){loading.postValue(false);}});TMDBClient.get().getSimilarMovies(id).enqueue(new Callback<Models.PagedResponse<Models.MovieResult>>(){public void onResponse(@NonNull Call<Models.PagedResponse<Models.MovieResult>>c,@NonNull Response<Models.PagedResponse<Models.MovieResult>>r){if(r.isSuccessful()&&r.body()!=null){List<ContentItem>l=new ArrayList<>();if(r.body().results!=null)for(Models.MovieResult m:r.body().results){ContentItem ci=new ContentItem();ci.id=m.id;ci.title=m.title;ci.posterPath=m.poster_path;ci.backdropPath=m.backdrop_path;ci.rating=m.vote_average;ci.mediaType="movie";l.add(ci);}similar.postValue(l);}}public void onFailure(@NonNull Call<Models.PagedResponse<Models.MovieResult>>c,@NonNull Throwable t){}});}\n    private void loadTV(int id){TMDBClient.get().getTVDetail(id,"credits").enqueue(new Callback<Models.TVDetail>(){public void onResponse(@NonNull Call<Models.TVDetail>c,@NonNull Response<Models.TVDetail>r){loading.postValue(false);if(r.isSuccessful()&&r.body()!=null){Models.TVDetail d=r.body();ContentItem ci=new ContentItem();ci.id=d.id;ci.name=d.name;ci.posterPath=d.poster_path;ci.backdropPath=d.backdrop_path;ci.rating=d.vote_average;ci.numberOfSeasons=d.number_of_seasons;ci.overview=d.overview;ci.releaseDate=d.first_air_date;ci.mediaType="tv";content.postValue(ci);loadSeason(d.id,1);}}public void onFailure(@NonNull Call<Models.TVDetail>c,@NonNull Throwable t){loading.postValue(false);}});TMDBClient.get().getSimilarTV(id).enqueue(new Callback<Models.PagedResponse<Models.TVResult>>(){public void onResponse(@NonNull Call<Models.PagedResponse<Models.TVResult>>c,@NonNull Response<Models.PagedResponse<Models.TVResult>>r){if(r.isSuccessful()&&r.body()!=null){List<ContentItem>l=new ArrayList<>();if(r.body().results!=null)for(Models.TVResult t:r.body().results){ContentItem ci=new ContentItem();ci.id=t.id;ci.name=t.name;ci.posterPath=t.poster_path;ci.backdropPath=t.backdrop_path;ci.rating=t.vote_average;ci.mediaType="tv";l.add(ci);}similar.postValue(l);}}public void onFailure(@NonNull Call<Models.PagedResponse<Models.TVResult>>c,@NonNull Throwable t){}});}\n    public void loadSeason(int tvId,int sn){TMDBClient.get().getSeason(tvId,sn).enqueue(new Callback<Models.SeasonDetail>(){public void onResponse(@NonNull Call<Models.SeasonDetail>c,@NonNull Response<Models.SeasonDetail>r){if(r.isSuccessful()&&r.body()!=null)season.postValue(r.body());}public void onFailure(@NonNull Call<Models.SeasonDetail>c,@NonNull Throwable t){}});}\n    public LiveData<ContentItem>getContent(){return content;}\n    public LiveData<List<ContentItem>>getSimilar(){return similar;}\n    public LiveData<Models.SeasonDetail>getSeason(){return season;}\n    public LiveData<Boolean>getLoading(){return loading;}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/ui/viewmodel/SearchViewModel.java'] = 'package com.fountainhome.streaming.ui.viewmodel;\nimport android.app.Application;\nimport androidx.annotation.NonNull;\nimport androidx.lifecycle.*;\nimport com.fountainhome.streaming.api.*;\nimport java.util.*;\nimport retrofit2.*;\npublic class SearchViewModel extends AndroidViewModel {\n    private final MutableLiveData<List<ContentItem>>results=new MutableLiveData<>();\n    public SearchViewModel(@NonNull Application app){super(app);}\n    public void search(String q){TMDBClient.get().search(q,1).enqueue(new Callback<Models.PagedResponse<Models.SearchResult>>(){public void onResponse(@NonNull Call<Models.PagedResponse<Models.SearchResult>>c,@NonNull Response<Models.PagedResponse<Models.SearchResult>>r){if(r.isSuccessful()&&r.body()!=null){List<ContentItem>l=new ArrayList<>();if(r.body().results!=null)for(Models.SearchResult sr:r.body().results){if("person".equals(sr.media_type))continue;ContentItem ci=new ContentItem();ci.id=sr.id;ci.title=sr.title;ci.name=sr.name;ci.posterPath=sr.poster_path;ci.mediaType=sr.media_type!=null?sr.media_type:"movie";ci.rating=sr.vote_average;l.add(ci);}results.postValue(l);}}public void onFailure(@NonNull Call<Models.PagedResponse<Models.SearchResult>>c,@NonNull Throwable t){}});}\n    public LiveData<List<ContentItem>>getResults(){return results;}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/ui/adapter/ContentAdapter.java'] = 'package com.fountainhome.streaming.ui.adapter;\nimport android.view.*;\nimport android.widget.Toast;\nimport androidx.annotation.NonNull;\nimport androidx.appcompat.app.AlertDialog;\nimport androidx.recyclerview.widget.*;\nimport com.bumptech.glide.Glide;\nimport com.bumptech.glide.load.engine.DiskCacheStrategy;\nimport com.bumptech.glide.request.RequestOptions;\nimport com.fountainhome.streaming.databinding.ItemPosterBinding;\nimport com.fountainhome.streaming.service.LibraryManager;\nimport com.fountainhome.streaming.service.SourceGenerator;\nimport com.fountainhome.streaming.ui.viewmodel.ContentItem;\npublic class ContentAdapter extends ListAdapter<ContentItem,ContentAdapter.VH> {\n    public interface OnClick{void onClick(ContentItem item);}\n    private final OnClick l;\n    public ContentAdapter(@NonNull OnClick l){super(new DiffUtil.ItemCallback<ContentItem>(){public boolean areItemsTheSame(@NonNull ContentItem a,@NonNull ContentItem b){return a.id==b.id;}public boolean areContentsTheSame(@NonNull ContentItem a,@NonNull ContentItem b){return a.id==b.id;}});this.l=l;}\n    @NonNull public VH onCreateViewHolder(@NonNull ViewGroup p,int t){return new VH(ItemPosterBinding.inflate(LayoutInflater.from(p.getContext()),p,false));}\n    public void onBindViewHolder(@NonNull VH h,int pos){\n        ContentItem item=getItem(pos);\n        h.b.titleText.setText(item.displayTitle());\n        h.b.ratingText.setText(item.rating>0?String.format("★%.1f",item.rating):"");\n        h.b.ratingText.setVisibility(item.rating>0?View.VISIBLE:View.GONE);\n        Glide.with(h.itemView).load(SourceGenerator.imageUrl(item.posterPath,"w342"))\n            .apply(new RequestOptions().diskCacheStrategy(DiskCacheStrategy.ALL).placeholder(android.R.color.darker_gray))\n            .centerCrop().into(h.b.posterImage);\n        h.itemView.setOnClickListener(v->l.onClick(item));\n        h.itemView.setOnLongClickListener(v->{\n            android.content.Context ctx=v.getContext();\n            boolean fav=LibraryManager.isIn(ctx,item.id,item.mediaType,LibraryManager.FAVORITES);\n            boolean wl=LibraryManager.isIn(ctx,item.id,item.mediaType,LibraryManager.WATCHLIST);\n            String[]opts={"Open",wl?"Remove from Watchlist":"Add to Watchlist",fav?"Remove from Favorites":"Add to Favorites","Share"};\n            new AlertDialog.Builder(ctx).setTitle(item.displayTitle()).setItems(opts,(d,w)->{switch(w){case 0:l.onClick(item);break;case 1:if(wl)LibraryManager.remove(ctx,item.id,item.mediaType,LibraryManager.WATCHLIST);else LibraryManager.add(ctx,item,LibraryManager.WATCHLIST);Toast.makeText(ctx,wl?"Removed":"Added to Watchlist",Toast.LENGTH_SHORT).show();break;case 2:LibraryManager.toggleFavorite(ctx,item);Toast.makeText(ctx,fav?"Removed":"Added to Favorites",Toast.LENGTH_SHORT).show();break;case 3:android.content.Intent si=new android.content.Intent(android.content.Intent.ACTION_SEND);si.setType("text/plain");si.putExtra(android.content.Intent.EXTRA_TEXT,item.displayTitle()+" — Fountain Home");ctx.startActivity(android.content.Intent.createChooser(si,"Share via"));break;}}).show();\n            return true;\n        });\n    }\n    static class VH extends RecyclerView.ViewHolder{final ItemPosterBinding b;VH(@NonNull ItemPosterBinding b){super(b.getRoot());this.b=b;}}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/ui/adapter/EpisodeAdapter.java'] = 'package com.fountainhome.streaming.ui.adapter;\nimport android.content.Context;\nimport android.view.*;\nimport android.widget.*;\nimport androidx.annotation.NonNull;\nimport androidx.recyclerview.widget.*;\nimport com.bumptech.glide.Glide;\nimport com.fountainhome.streaming.R;\nimport com.fountainhome.streaming.api.Models;\nimport com.fountainhome.streaming.download.DownloadManager2;\nimport com.fountainhome.streaming.service.*;\nimport java.util.List;\npublic class EpisodeAdapter extends RecyclerView.Adapter<EpisodeAdapter.VH> {\n    public interface OnEpClick{void onClick(Models.Episode ep,int num);}\n    private final List<Models.Episode>eps;private final OnEpClick l;private final int tmdbId;private final String type;private final int season;private final Context ctx;\n    public EpisodeAdapter(List<Models.Episode>eps,OnEpClick l,int tmdbId,String type,int season,Context ctx){this.eps=eps;this.l=l;this.tmdbId=tmdbId;this.type=type;this.season=season;this.ctx=ctx;}\n    @NonNull public VH onCreateViewHolder(@NonNull ViewGroup p,int t){return new VH(LayoutInflater.from(p.getContext()).inflate(R.layout.item_episode,p,false));}\n    public void onBindViewHolder(@NonNull VH h,int pos){Models.Episode ep=eps.get(pos);int num=ep.episode_number>0?ep.episode_number:pos+1;h.num.setText("E"+num);h.title.setText(ep.name!=null?ep.name:"Episode "+num);if(ep.overview!=null&&!ep.overview.isEmpty()){h.overview.setText(ep.overview);h.overview.setVisibility(View.VISIBLE);}else h.overview.setVisibility(View.GONE);if(ep.runtime>0){h.duration.setText(ep.runtime+"m");h.duration.setVisibility(View.VISIBLE);}Glide.with(ctx).load(SourceGenerator.imageUrl(ep.still_path,"w300")).placeholder(android.R.color.darker_gray).into(h.thumb);boolean dl=DownloadManager2.isDownloaded(ctx,tmdbId,type,season,num);h.dlIcon.setImageResource(dl?R.drawable.ic_check:R.drawable.ic_download);h.dlIcon.setAlpha(dl?1f:0.5f);long prog=WatchProgress.get(ctx,tmdbId,type,season,num);h.progress.setVisibility(prog>0?View.VISIBLE:View.GONE);h.itemView.setOnClickListener(v->l.onClick(ep,num));}\n    public int getItemCount(){return eps.size();}\n    static class VH extends RecyclerView.ViewHolder{TextView num,title,overview,duration;ImageView thumb,dlIcon;View progress;VH(View v){super(v);num=v.findViewById(R.id.ep_number);title=v.findViewById(R.id.ep_title);overview=v.findViewById(R.id.ep_overview);duration=v.findViewById(R.id.ep_duration);thumb=v.findViewById(R.id.ep_thumbnail);dlIcon=v.findViewById(R.id.download_icon);progress=v.findViewById(R.id.ep_progress);}}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/anime/AniListClient.java'] = 'package com.fountainhome.streaming.anime;\nimport android.os.Handler;\nimport android.os.Looper;\nimport com.google.gson.*;\nimport okhttp3.*;\nimport java.io.IOException;\nimport java.util.*;\nimport java.util.concurrent.ExecutorService;\nimport java.util.concurrent.Executors;\npublic class AniListClient {\n    private static final String URL="https://graphql.anilist.co";\n    private static final OkHttpClient client=new OkHttpClient();\n    private static final ExecutorService exec=Executors.newCachedThreadPool();\n    private static final Handler mh=new Handler(Looper.getMainLooper());\n    public interface Callback<T>{void onSuccess(T r);void onError(String e);}\n    public static class AnimeItem{public int id,episodes,seasonYear;public String titleEnglish,titleRomaji,coverImage,bannerImage,description,status,season,format;public double averageScore;public List<String>genres=new ArrayList<>();public String displayTitle(){return titleEnglish!=null&&!titleEnglish.isEmpty()?titleEnglish:(titleRomaji!=null?titleRomaji:"");}}\n    private static String q(String gql,String vars)throws IOException{\n        String body="{"query":""+gql.replace(""","\\"").replace("\n"," ")+"","variables":"+vars+"}";\n        Request req=new Request.Builder().url(URL).addHeader("Content-Type","application/json").addHeader("Accept","application/json").post(RequestBody.create(body,MediaType.parse("application/json"))).build();\n        try(Response res=client.newCall(req).execute()){if(res.body()!=null)return res.body().string();}return "{}";\n    }\n    private static List<AnimeItem>parse(JsonArray arr){List<AnimeItem>items=new ArrayList<>();for(JsonElement el:arr){try{JsonObject o=el.getAsJsonObject();AnimeItem a=new AnimeItem();a.id=gi(o,"id",0);JsonObject t=o.has("title")&&!o.get("title").isJsonNull()?o.getAsJsonObject("title"):null;if(t!=null){a.titleEnglish=gs(t,"english");a.titleRomaji=gs(t,"romaji");}JsonObject ci=o.has("coverImage")&&!o.get("coverImage").isJsonNull()?o.getAsJsonObject("coverImage"):null;if(ci!=null)a.coverImage=gs(ci,"large");a.bannerImage=gs(o,"bannerImage");a.description=gs(o,"description");a.episodes=gi(o,"episodes",0);double sc=gd(o,"averageScore");a.averageScore=sc>0?sc/10.0:0;a.status=gs(o,"status");a.season=gs(o,"season");a.seasonYear=gi(o,"seasonYear",0);a.format=gs(o,"format");if(o.has("genres")&&o.get("genres").isJsonArray())for(JsonElement g:o.getAsJsonArray("genres"))a.genres.add(g.getAsString());items.add(a);}catch(Exception ignored){}}return items;}\n    private static String gs(JsonObject o,String k){return o.has(k)&&!o.get(k).isJsonNull()?o.get(k).getAsString():"";}\n    private static int gi(JsonObject o,String k,int d){try{return o.has(k)&&!o.get(k).isJsonNull()?o.get(k).getAsInt():d;}catch(Exception e){return d;}}\n    private static double gd(JsonObject o,String k){try{return o.has(k)&&!o.get(k).isJsonNull()?o.get(k).getAsDouble():0;}catch(Exception e){return 0;}}\n    private static void run(String gql,String vars,Callback<List<AnimeItem>>cb){exec.execute(()->{try{String res=q(gql,vars);JsonArray arr=JsonParser.parseString(res).getAsJsonObject().getAsJsonObject("data").getAsJsonObject("Page").getAsJsonArray("media");mh.post(()->cb.onSuccess(parse(arr)));}catch(Exception e){mh.post(()->cb.onError(e.getMessage()));}});}\n    public static void getTrending(Callback<List<AnimeItem>>cb){run("query{Page(page:1,perPage:20){media(sort:TRENDING_DESC,type:ANIME,isAdult:false){id title{english romaji}coverImage{large}bannerImage description episodes averageScore status season seasonYear format genres}}}","{}",cb);}\n    public static void getPopular(Callback<List<AnimeItem>>cb){run("query{Page(page:1,perPage:20){media(sort:POPULARITY_DESC,type:ANIME,isAdult:false){id title{english romaji}coverImage{large}episodes averageScore status format genres}}}","{}",cb);}\n    public static void getThisSeason(Callback<List<AnimeItem>>cb){run("query{Page(page:1,perPage:20){media(season:SPRING,seasonYear:2025,type:ANIME,sort:POPULARITY_DESC,isAdult:false){id title{english romaji}coverImage{large}episodes averageScore status format}}}","{}",cb);}\n    public static void search(String kw,Callback<List<AnimeItem>>cb){run("query($s:String){Page(page:1,perPage:20){media(search:$s,type:ANIME,isAdult:false){id title{english romaji}coverImage{large}episodes averageScore status format genres}}}","{"s":""+kw.replace(""","")+""}",cb);}\n}\n'

java_files['app/src/main/java/com/fountainhome/streaming/anime/AnimeAdapter.java'] = 'package com.fountainhome.streaming.anime;\nimport android.view.*;\nimport androidx.annotation.NonNull;\nimport androidx.recyclerview.widget.*;\nimport com.bumptech.glide.Glide;\nimport com.fountainhome.streaming.databinding.ItemAnimeBinding;\npublic class AnimeAdapter extends ListAdapter<AniListClient.AnimeItem,AnimeAdapter.VH> {\n    public interface OnClick{void onClick(AniListClient.AnimeItem item);}\n    private final OnClick l;\n    public AnimeAdapter(@NonNull OnClick l){super(new DiffUtil.ItemCallback<AniListClient.AnimeItem>(){public boolean areItemsTheSame(@NonNull AniListClient.AnimeItem a,@NonNull AniListClient.AnimeItem b){return a.id==b.id;}public boolean areContentsTheSame(@NonNull AniListClient.AnimeItem a,@NonNull AniListClient.AnimeItem b){return a.id==b.id;}});this.l=l;}\n    @NonNull public VH onCreateViewHolder(@NonNull ViewGroup p,int t){return new VH(ItemAnimeBinding.inflate(LayoutInflater.from(p.getContext()),p,false));}\n    public void onBindViewHolder(@NonNull VH h,int pos){AniListClient.AnimeItem item=getItem(pos);h.b.titleText.setText(item.displayTitle());h.b.ratingText.setText(item.averageScore>0?String.format("★%.1f",item.averageScore):"");h.b.episodesText.setText(item.episodes>0?item.episodes+" eps":(item.status!=null?item.status:""));Glide.with(h.itemView).load(item.coverImage).placeholder(android.R.color.darker_gray).centerCrop().into(h.b.posterImage);h.itemView.setOnClickListener(v->l.onClick(item));}\n    static class VH extends RecyclerView.ViewHolder{final ItemAnimeBinding b;VH(@NonNull ItemAnimeBinding b){super(b.getRoot());this.b=b;}}\n}\n'

